/// <summary>
/// This is extension class for form <c>CustTable</c>, datasource <c>CustTable</c> and Data field <c>ETGApplicableTradeLimit<\c>
/// </summary>
[ExtensionOf(formDataFieldStr(CustTable, CustTable, ETGApplicableTradeLimit))]
internal final class ETGCustTableFDS_ApplicableTradeLimit_Extension
{
}

Method.Source:
public void modified()
{
    if (ETGACFParameters::find().EnableTradeLimit == NoYes::Yes)
    {
        FormDataSource custTableDS = this.datasource() as FormDataSource;
        CustTable custTable = custTableDS.cursor();
        FormDataObject tradeLimitDataField = custTableDS.object(fieldNum(CustTable, ETGTradeLimitSalesReal));

        if (custTable.ETGApplicableTradeLimit == NoYes::No && custTable.ETGTradeLimitSalesReal > 0)
        {
            warning("@ETG_New:ApplicableTradeLimitWarning");
            custTable.ETGApplicableTradeLimit = NoYes::Yes;
        }

        if (tradeLimitDataField)
        {
            tradeLimitDataField.allowEdit(custTable.ETGApplicableTradeLimit == NoYes::Yes);
        }
    }

    next modified();
}
